  // Listener fires only once
  once(event: string, listener: Listener): void {
    if (!this._listeners.has(event)) {
      this._listeners.set(event, []);
    }
    this._listeners.get(event)!.push({ listener, once: true });
  }

  // Call all listeners, return true if any existed
  emit(event: string, ...args: unknown[]): boolean {
    const entries = this._listeners.get(event);
    if (!entries || entries.length === 0) return false;

    // Snapshot before iterating so mid-emit removals don't disrupt the loop
    const snapshot = [...entries];
    for (const entry of snapshot) {
      if (entry.once) {
        // Remove from the live list before calling to prevent double-fire
        this.off(event, entry.listener);
      }
      entry.listener(...args);
    }
    return true;
  }

  // Remove specific listener
  off(event: string, listener: Listener): void {
    const entries = this._listeners.get(event);
    if (!entries) return;
    const idx = entries.findIndex((e) => e.listener === listener);
    if (idx !== -1) {
      entries.splice(idx, 1);
    }
    // Clean up empty event keys so eventNames() stays accurate
    if (entries.length === 0) {
      this._listeners.delete(event);
    }
  }

  // Remove all or per-event listeners
  removeAllListeners(event?: string): void {
    if (event === undefined) {
      this._listeners.clear();
    } else {
      this._listeners.delete(event);
    }
  }

  // Return count of listeners for event
  listenerCount(event: string): number {
    return this._listeners.get(event)?.length ?? 0;
  }

  // Return array of events with listeners
  eventNames(): string[] {
    return [...this._listeners.keys()];
  }
}

